/// Paint a smooth, semi-transparent loading spinner in the bottom-right corner
/// of the given rectangle.  The spinner is a rotating arc that indicates
/// background frame decoding is in progress.
///
/// * `painter` – the egui painter to draw on.
/// * `rect`    – bounding rectangle of the image being loaded.
/// * `time`    – monotonic time in seconds (e.g. `ctx.input(|i| i.time)`).
fn paint_loading_spinner(painter: &egui::Painter, rect: egui::Rect, time: f64) {
    let margin = 16.0;
    let radius = 10.0;
    let center = egui::pos2(
        rect.right() - margin - radius,
        rect.bottom() - margin - radius,
    );

    // Semi-transparent background disc so the spinner is visible on any image.
    painter.circle_filled(
        center,
        radius + 4.0,
        egui::Color32::from_rgba_unmultiplied(0, 0, 0, 100),
    );

    // Faint track ring.
    painter.circle_stroke(
        center,
        radius,
        egui::Stroke::new(
            2.0,
            egui::Color32::from_rgba_unmultiplied(255, 255, 255, 35),
        ),
    );

    // Spinning arc — approximated with a polyline.
    let start_angle = (time * 4.0) as f32; // ~4 rad/s ≈ 0.64 rev/s
    let sweep = std::f32::consts::PI * 1.4; // ~250°
    let segments = 28;
    let points: SmallVec<[egui::Pos2; 32]> = (0..=segments)
        .map(|i| {
            let t = i as f32 / segments as f32;
            let angle = start_angle + sweep * t;
            center + radius * egui::vec2(angle.cos(), angle.sin())
        })
        .collect();
    let stroke = egui::Stroke::new(
        2.5,
        egui::Color32::from_rgba_unmultiplied(255, 255, 255, 200),
    );
    painter.add(egui::Shape::line(points.to_vec(), stroke));
}

fn paint_static_hourglass_placeholder(
    painter: &egui::Painter,
    rect: egui::Rect,
    corner_radius: f32,
) {
    painter.rect_filled(rect, corner_radius, egui::Color32::from_gray(30));
    let font_size = (rect.width().min(rect.height()) * 0.38).clamp(10.0, 24.0);
    painter.text(
        rect.center(),
        egui::Align2::CENTER_CENTER,
        "⏳",
        egui::FontId::proportional(font_size),
        egui::Color32::from_gray(80),
    );
}

fn rotate_quad_point(center: egui::Pos2, local: egui::Vec2, angle_radians: f32) -> egui::Pos2 {
    let (sin, cos) = angle_radians.sin_cos();
    center + egui::vec2(local.x * cos - local.y * sin, local.x * sin + local.y * cos)
}

fn rotated_bounding_size(size: egui::Vec2, angle_radians: f32) -> egui::Vec2 {
    let sin = angle_radians.sin().abs();
    let cos = angle_radians.cos().abs();

    egui::vec2(size.x * cos + size.y * sin, size.x * sin + size.y * cos)
}

fn paint_rotated_texture(
    painter: &egui::Painter,
    texture_id: egui::TextureId,
    center: egui::Pos2,
    size: egui::Vec2,
    angle_radians: f32,
    flip_horizontal: bool,
    flip_vertical: bool,
    tint: egui::Color32,
) {
    let half = size * 0.5;
    let local_corners = [
        egui::vec2(-half.x, -half.y),
        egui::vec2(half.x, -half.y),
        egui::vec2(half.x, half.y),
        egui::vec2(-half.x, half.y),
    ];
    let u_min = if flip_horizontal { 1.0 } else { 0.0 };
    let u_max = if flip_horizontal { 0.0 } else { 1.0 };
    let v_min = if flip_vertical { 1.0 } else { 0.0 };
    let v_max = if flip_vertical { 0.0 } else { 1.0 };
    let uvs = [
        egui::pos2(u_min, v_min),
        egui::pos2(u_max, v_min),
        egui::pos2(u_max, v_max),
        egui::pos2(u_min, v_max),
    ];

    let mut mesh = egui::epaint::Mesh::with_texture(texture_id);
    let base = mesh.vertices.len() as u32;
    for (local, uv) in local_corners.into_iter().zip(uvs) {
        mesh.vertices.push(egui::epaint::Vertex {
            pos: rotate_quad_point(center, local, angle_radians),
            uv,
            color: tint,
        });
    }
    mesh.indices
        .extend_from_slice(&[base, base + 1, base + 2, base, base + 2, base + 3]);

    painter.add(egui::Shape::mesh(mesh));
}

/// Downscale RGBA pixel data if it exceeds the maximum texture size.
/// Uses Cow to avoid unnecessary allocations when no downscaling is needed.
/// Uses Triangle filter (faster than Lanczos3) for better performance.
fn image_filter_to_fir(filter: FilterType) -> fir::FilterType {
    match filter {
        FilterType::Nearest => fir::FilterType::Box,
        FilterType::Triangle => fir::FilterType::Bilinear,
        FilterType::CatmullRom => fir::FilterType::CatmullRom,
        FilterType::Gaussian => fir::FilterType::Gaussian,
        FilterType::Lanczos3 => fir::FilterType::Lanczos3,
    }
}

fn resize_rgba_with_fir(
    width: u32,
    height: u32,
    pixels: &[u8],
    new_w: u32,
    new_h: u32,
    filter: FilterType,
) -> Option<Vec<u8>> {
    let src = fir::images::ImageRef::new(width, height, pixels, fir::PixelType::U8x4).ok()?;
    let mut dst = fir::images::Image::new(new_w, new_h, fir::PixelType::U8x4);

    let options = fir::ResizeOptions::new()
        .resize_alg(fir::ResizeAlg::Convolution(image_filter_to_fir(filter)));

    let mut resizer = fir::Resizer::new();
    resizer.resize(&src, &mut dst, Some(&options)).ok()?;
    Some(dst.into_vec())
}

fn downscale_rgba_if_needed<'a>(
    width: u32,
    height: u32,
    pixels: &'a [u8],
    max_texture_side: u32,
    filter: image::imageops::FilterType,
) -> (u32, u32, Cow<'a, [u8]>) {
    use image::imageops::FilterType;

    if max_texture_side == 0 {
        return (width, height, Cow::Borrowed(pixels));
    }

    if width <= max_texture_side && height <= max_texture_side {
        return (width, height, Cow::Borrowed(pixels));
    }

    // Preserve aspect ratio; clamp to at least 1x1.
    let scale =
        (max_texture_side as f64 / width as f64).min(max_texture_side as f64 / height as f64);
    let new_w = ((width as f64) * scale).round().max(1.0) as u32;
    let new_h = ((height as f64) * scale).round().max(1.0) as u32;

    let filter = match filter {
        // Be defensive: always downscaling here, so avoid an accidental "upscale"-only filter.
        // (All current variants are valid for both directions, but keep this guard for future changes.)
        FilterType::Nearest
        | FilterType::Triangle
        | FilterType::CatmullRom
        | FilterType::Gaussian
        | FilterType::Lanczos3 => filter,
    };

    if let Some(resized) = resize_rgba_with_fir(width, height, pixels, new_w, new_h, filter) {
        return (new_w, new_h, Cow::Owned(resized));
    }

    // Convert to an owned buffer only for the fallback resize path.
    let Some(img) = image::RgbaImage::from_raw(width, height, pixels.to_vec()) else {
        return (width, height, Cow::Borrowed(pixels));
    };

    let resized = image::imageops::resize(&img, new_w, new_h, filter);
    (new_w, new_h, Cow::Owned(resized.into_raw()))
}

fn try_color_image_from_opaque_rgba_bytes(
    size: [usize; 2],
    pixels: Bytes,
) -> Result<egui::ColorImage, Bytes> {
    let expected_len = size[0].saturating_mul(size[1]).saturating_mul(4);
    if expected_len != pixels.len() {
        return Err(pixels);
    }

    let pixels_mut = match pixels.try_into_mut() {
        Ok(pixels_mut) => pixels_mut,
        Err(pixels) => return Err(pixels),
    };
    let pixels_vec: Vec<u8> = pixels_mut.into();
    if pixels_vec.capacity() % std::mem::size_of::<egui::Color32>() != 0 {
        return Err(Bytes::from(pixels_vec));
    }

    // Video frames negotiated as RGBA are opaque. Color32 has the same byte layout
    // for opaque sRGBA, so this avoids egui's per-pixel conversion loop.
    debug_assert_eq!(std::mem::size_of::<egui::Color32>(), 4);
    debug_assert_eq!(std::mem::align_of::<egui::Color32>(), 1);
    let mut pixels_vec = std::mem::ManuallyDrop::new(pixels_vec);
    let color_len = pixels_vec.len() / 4;
    let color_cap = pixels_vec.capacity() / 4;
    let color_ptr = pixels_vec.as_mut_ptr() as *mut egui::Color32;
    let pixels = unsafe { Vec::from_raw_parts(color_ptr, color_len, color_cap) };

    Ok(egui::ColorImage { size, pixels })
}

fn cached_or_probe_video_dimensions(path: &Path) -> Option<(u32, u32)> {
    if let Some(dims) = lookup_cached_dimensions(path, CachedMediaKind::Video) {
        return Some(dims);
    }

    if gstreamer_runtime_available() {
        if let Some(dims) = probe_video_dimensions_with_gstreamer(path) {
            if dims.0 > 0 && dims.1 > 0 {
                store_cached_dimensions(path, CachedMediaKind::Video, dims.0, dims.1);
                return Some(dims);
            }
        }
    }

    let dims = probe_video_dimensions_without_gstreamer(path)?;
    if dims.0 > 0 && dims.1 > 0 {
        store_cached_dimensions(path, CachedMediaKind::Video, dims.0, dims.1);
        Some(dims)
    } else {
        None
    }
}

fn even_video_dimension(value: f64, source_limit: u32) -> u32 {
    let mut dimension = value.round().clamp(1.0, source_limit.max(1) as f64) as u32;
    if dimension > 1 && dimension % 2 != 0 {
        dimension -= 1;
    }
    dimension.max(1)
}

fn video_output_dimensions_for_bounds(
    source_dimensions: Option<(u32, u32)>,
    output_bounds: Option<(u32, u32)>,
) -> Option<(u32, u32)> {
    let (source_w, source_h) = source_dimensions?;
    let (bound_w, bound_h) = output_bounds?;
    if source_w == 0 || source_h == 0 || bound_w == 0 || bound_h == 0 {
        return None;
    }

    let scale = (bound_w as f64 / source_w as f64)
        .min(bound_h as f64 / source_h as f64)
        .min(1.0);
    if scale >= 0.999 {
        return None;
    }

    Some((
        even_video_dimension(source_w as f64 * scale, source_w),
        even_video_dimension(source_h as f64 * scale, source_h),
    ))
}

#[cfg(target_os = "windows")]
fn windows_cjk_font_candidates() -> [(&'static str, &'static str); 6] {
    [
        // Japanese
        ("cjk_meiryo", r"C:\Windows\Fonts\meiryo.ttc"),
        ("cjk_msgothic", r"C:\Windows\Fonts\msgothic.ttc"),
        // Simplified Chinese
        ("cjk_msyh", r"C:\Windows\Fonts\msyh.ttc"),
        // Traditional Chinese
        ("cjk_msjh", r"C:\Windows\Fonts\msjh.ttc"),
        // Korean
        ("cjk_malgun", r"C:\Windows\Fonts\malgun.ttf"),
        // Broad fallback (varies by Windows install)
        ("cjk_segoeui", r"C:\Windows\Fonts\segoeui.ttf"),
    ]
}

#[cfg(target_os = "windows")]
fn load_windows_cjk_font_data() -> Vec<(String, Vec<u8>)> {
    let mut loaded = Vec::new();
    for (name, path) in windows_cjk_font_candidates() {
        if let Ok(bytes) = std::fs::read(path) {
            loaded.push((name.to_owned(), bytes));
        }
    }
    loaded
}

#[cfg(target_os = "windows")]
fn apply_windows_cjk_fonts(ctx: &egui::Context, font_data: Vec<(String, Vec<u8>)>) -> bool {
    // egui's default font set is Latin-focused; without adding a font that contains
    // CJK glyphs, filenames will show as tofu boxes in our custom title bar.
    let mut fonts = egui::FontDefinitions::default();

    let mut loaded_any = false;
    for (name, bytes) in font_data {
        fonts
            .font_data
            .insert(name.clone(), egui::FontData::from_owned(bytes));

        // Put CJK fonts first so they are preferred for matching glyphs.
        if let Some(family) = fonts.families.get_mut(&egui::FontFamily::Proportional) {
            if !family.iter().any(|f| f == &name) {
                family.insert(0, name.clone());
            }
        }
        if let Some(family) = fonts.families.get_mut(&egui::FontFamily::Monospace) {
            if !family.iter().any(|f| f == &name) {
                family.push(name.clone());
            }
        }

        loaded_any = true;
    }

    if loaded_any {
        ctx.set_fonts(fonts);
    }

    loaded_any
}

#[cfg(not(target_os = "windows"))]
fn load_windows_cjk_font_data() -> Vec<(String, Vec<u8>)> {
    Vec::new()
}

#[cfg(not(target_os = "windows"))]
fn apply_windows_cjk_fonts(_ctx: &egui::Context, _font_data: Vec<(String, Vec<u8>)>) -> bool {
    false
}

fn open_path_in_default_app(path: &std::path::Path) -> std::io::Result<()> {
    #[cfg(target_os = "windows")]
    {
        const CREATE_NO_WINDOW: u32 = 0x0800_0000;
        std::process::Command::new("cmd")
            .creation_flags(CREATE_NO_WINDOW)
            .args(["/C", "start", ""])
            .arg(path)
            .spawn()
            .map(|_| ())
    }

    #[cfg(target_os = "macos")]
    {
        std::process::Command::new("open")
            .arg(path)
            .spawn()
            .map(|_| ())
    }

    #[cfg(all(unix, not(target_os = "macos")))]
    {
        std::process::Command::new("xdg-open")
            .arg(path)
            .spawn()
            .map(|_| ())
    }
}

#[cfg(target_os = "windows")]
fn sh_open_folder_and_select_item(path: &Path) -> std::io::Result<()> {
    let mut should_uninitialize = false;

    // Shell selection APIs are COM-based. If COM is already initialized on this thread with
    // another model, continue (RPC_E_CHANGED_MODE). For any other failure, abort early.
    unsafe {
        let hr = CoInitializeEx(None, COINIT_APARTMENTTHREADED);
        if hr.is_ok() {
            should_uninitialize = true;
        } else if hr != RPC_E_CHANGED_MODE {
            return Err(std::io::Error::new(
                std::io::ErrorKind::Other,
                format!("CoInitializeEx failed before shell selection: {hr:?}"),
            ));
        }
    }

    let wide_path: Vec<u16> = path
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();

    let pidl = unsafe { ILCreateFromPathW(PCWSTR(wide_path.as_ptr())) };
    if pidl.is_null() {
        if should_uninitialize {
            unsafe {
                CoUninitialize();
            }
        }
        return Err(std::io::Error::new(
            std::io::ErrorKind::Other,
            "ILCreateFromPathW failed: could not create PIDL from path",
        ));
    }

    let select_result = unsafe { SHOpenFolderAndSelectItems(pidl as *const _, None, 0) };

    unsafe {
        ILFree(Some(pidl as *const _));
    }

    if should_uninitialize {
        unsafe {
            CoUninitialize();
        }
    }

    select_result.map_err(|e| {
        std::io::Error::new(
            std::io::ErrorKind::Other,
            format!("SHOpenFolderAndSelectItems failed: {e}"),
        )
    })
}

#[cfg(target_os = "windows")]
const EXPLORER_SELECT_RETRY_ATTEMPTS: usize = 5;
#[cfg(target_os = "windows")]
const EXPLORER_SELECT_RETRY_DELAY: Duration = Duration::from_millis(300);

#[cfg(target_os = "windows")]
fn spawn_explorer_select_retries(path: PathBuf) {
    // Explorer can open a new folder window asynchronously and drop the first
    // selection signal. Re-issuing selection a few times avoids that race.
    std::thread::spawn(move || {
        for _ in 1..EXPLORER_SELECT_RETRY_ATTEMPTS {
            std::thread::sleep(EXPLORER_SELECT_RETRY_DELAY);
            let _ = sh_open_folder_and_select_item(path.as_path());
        }
    });
}

fn reveal_path_in_file_explorer(path: &Path) -> std::io::Result<()> {
    #[cfg(target_os = "windows")]
    {
        let resolved_path = if path.is_absolute() {
            path.to_path_buf()
        } else {
            std::env::current_dir()?.join(path)
        };

        let is_directory = resolved_path.is_dir();

        let target_dir = if is_directory {
            resolved_path.clone()
        } else {
            resolved_path
                .parent()
                .map(Path::to_path_buf)
                .unwrap_or_else(|| resolved_path.clone())
        };

        if !target_dir.exists() {
            return Err(std::io::Error::new(
                std::io::ErrorKind::NotFound,
                format!("Path does not exist: {}", target_dir.display()),
            ));
        }

        if is_directory {
            return std::process::Command::new("explorer.exe")
                .arg(&target_dir)
                .spawn()
                .map(|_| ());
        }

        let retry_path = resolved_path.clone();
        match sh_open_folder_and_select_item(&resolved_path) {
            Ok(_) => {
                spawn_explorer_select_retries(retry_path);
                Ok(())
            }
            Err(select_err) => std::process::Command::new("explorer.exe")
                .arg(&target_dir)
                .spawn()
                .map(|_| {
                    spawn_explorer_select_retries(resolved_path.clone());
                })
                .map_err(|folder_err| {
                    std::io::Error::new(
                        std::io::ErrorKind::Other,
                        format!(
                            "Failed to select file in Explorer: {}; fallback opening folder failed: {}",
                            select_err, folder_err
                        ),
                    )
                }),
        }
    }

    #[cfg(target_os = "macos")]
    {
        let directory = if path.is_dir() {
            path.to_path_buf()
        } else {
            path.parent().unwrap_or(path).to_path_buf()
        };
        std::process::Command::new("open")
            .arg(directory)
            .spawn()
            .map(|_| ())
    }

    #[cfg(all(unix, not(target_os = "macos")))]
    {
        let directory = if path.is_dir() {
            path.to_path_buf()
        } else {
            path.parent().unwrap_or(path).to_path_buf()
        };
        std::process::Command::new("xdg-open")
            .arg(directory)
            .spawn()
            .map(|_| ())
    }
}

